## 2. `blocksci_stubs.cpp` – C/C++ glue

```cpp
/* ----------------------------------------------------------------------
   blocksci_stubs.cpp   –  OCaml <-> BlockSci binding
   ---------------------------------------------------------------------- */

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include <blocksci/chain/chain.hpp>       // BlockSci public API
#include <blocksci/cluster/cluster.hpp>
#include <blocksci/heuristics/heuristics.hpp>

#include <string>
#include <cstring>
#include <cstdlib>

/* ----------------------------------------------------------------------
   Global state
   ---------------------------------------------------------------------- */
static blocksci::Chain *g_chain = nullptr;

/* ----------------------------------------------------------------------
   OCaml representation of a block
   ---------------------------------------------------------------------- */
struct ocaml_block {
  int64_t height;      // block height
  char *hash;          // null‑terminated hex string (malloc’ed)
  double timestamp;    // Unix time
};

/* Finaliser for the custom block value – frees the duplicated hash string */
static void block_finalize(value v) {
  ocaml_block *b = (ocaml_block *)Data_custom_val(v);
  if (b->hash) std::free(b->hash);
}

/* Custom operations descriptor – only a finaliser is needed */
static struct custom_operations block_ops = {
  "blocksci.block",
  block_finalize,
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default
};

/* ----------------------------------------------------------------------
   Helper: allocate a fresh OCaml block value from a BlockSci block
   ---------------------------------------------------------------------- */
static value caml_alloc_block(const blocksci::Block &blk) {
  CAMLparam0();
  CAMLlocal1(v);

  v = caml_alloc_custom(&block_ops, sizeof(ocaml_block), 0, 1);
  ocaml_block *b = (ocaml_block *)Data_custom_val(v);

  b->height = static_cast<int64_t>(blk.height());
  b->timestamp = blk.timestamp();

  // BlockSci gives the hash as a std::string (binary).  We expose the
  // hexadecimal representation because that is what most users expect.
  std::string hex = blk.hash().toHex();          // e.g. "00000000..."
  b->hash = static_cast<char *>(std::malloc(hex.size() + 1));
  if (!b->hash) caml_failwith("malloc failed in caml_alloc_block");
  std::memcpy(b->hash, hex.c_str(), hex.size() + 1);

  CAMLreturn(v);
}

/* ----------------------------------------------------------------------
   OCaml entry points
   ---------------------------------------------------------------------- */

/* Initialise the BlockSci chain */
extern "C" CAMLprim value caml_blocksci_init(value v_path) {
  CAMLparam1(v_path);
  const char *c_path = String_val(v_path);

  if (g_chain != nullptr) caml_failwith("BlockSci already initialised");
  try {
    g_chain = new blocksci::Chain(c_path);
  } catch (const std::exception &e) {
    caml_failwith(e.what());
  }

  CAMLreturn(Val_unit);
}

/* Close the chain and free resources */
extern "C" CAMLprim value caml_blocksci_close(value v_unit) {
  CAMLparam1(v_unit);
  (void)v_unit;   // unused

  if (g_chain) {
    delete g_chain;
    g_chain = nullptr;
  }

  CAMLreturn(Val_unit);
}

/* Iterate over all blocks, calling the supplied OCaml closure on each one */
extern "C" CAMLprim value caml_blocksci_iter_blocks(value v_cb) {
  CAMLparam1(v_cb);
  if (g_chain == nullptr) caml_failwith("BlockSci not initialised");

  /* The iteration itself runs without the OCaml runtime lock – it is
     pure C++ code.  We acquire the lock only when we need to call back
     into OCaml. */
  caml_release_runtime_system();

  try {
    for (const auto &blk : *g_chain) {
      /* Switch back to OCaml to invoke the user callback */
      caml_acquire_runtime_system();
      CAMLlocal1(v_block);
      v_block = caml_alloc_block(blk);
      caml_callback(v_cb, v_block);
      caml_release_runtime_system();
    }
  } catch (const std::exception &e) {
    caml_acquire_runtime_system();
    caml_failwith(e.what());
  }

  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Accessors – they operate on the opaque custom value
   ---------------------------------------------------------------------- */

extern "C" CAMLprim value caml_block_height(value v_block) {
  CAMLparam1(v_block);
  ocaml_block *b = (ocaml_block *)Data_custom_val(v_block);
  CAMLreturn(caml_copy_int64(b->height));
}

extern "C" CAMLprim value caml_block_hash(value v_block) {
  CAMLparam1(v_block);
  ocaml_block *b = (ocaml_block *)Data_custom_val(v_block);
  /* The stored string is already NUL‑terminated */
  CAMLreturn(caml_copy_string(b->hash));
}

extern "C" CAMLprim value caml_block_timestamp(value v_block) {
  CAMLparam1(v_block);
  ocaml_block *b = (ocaml_block *)Data_custom_val(v_block);
  CAMLreturn(caml_copy_double(b->timestamp));
}
```

### Important notes about the stub

* **C++ compilation** – the file must be compiled as C++ (`g++`/`clang++`) because it includes BlockSci headers and uses C++ constructs.  
* **Thread safety** – the iterator runs without the OCaml runtime lock (`caml_release_runtime_system`).  The lock is reacquired for each callback, so user code can allocate, raise, etc.  If you need a truly *single* callback (e.g. to avoid lock‑thrashing), you can move the `caml_acquire_runtime_system` out of the loop, but then the callback must be extremely fast.  
* **Memory management** – the only heap allocation we keep per block is the duplicated hash string; it is freed by `block_finalize`.  All other fields are stored directly inside the custom block.  
* **Error handling** – any C++ exception is turned into an OCaml failure with `caml_failwith`.  If the OCaml callback raises, the exception propagates out of `iter_blocks` and aborts the iteration.

