## 3. Build instructions (Makefile fragment)

```make
# --------------------------------------------------------------
#   Build the BlockSci OCaml binding
# --------------------------------------------------------------
OCAMLFLAGS   = -thread -g
OCAMLLIBS    = -cclib -lstdc++ -cclib -lblocksci   # adjust lib name if needed
CXXFLAGS     = -O2 -Wall -fPIC $(shell ocamlc -config | grep cflags | cut -d: -f2)

# The generated .cmi/.cmo/.cmx files
LIB_OBJS    = blocksci_stubs.o

all: libblocksci.a blocksci.cma blocksci.cmxa

# ----------------------------------------------------------------
#   Compile the C++ stub
# ----------------------------------------------------------------
blocksci_stubs.o: blocksci_stubs.cpp
	$(CXX) $(CXXFLAGS) -I$(shell ocamlc -where) -c $< -o $@

# ----------------------------------------------------------------
#   Static library (for ocamlc)
# ----------------------------------------------------------------
libblocksci.a: $(LIB_OBJS)
	ar rcs $@ $^

# ----------------------------------------------------------------
#   Bytecode library (ocamlc)
# ----------------------------------------------------------------
blocksci.cma: libblocksci.a blocksci.cmi
	ocamlc -a -o $@ $^

# ----------------------------------------------------------------
#   Native library (ocamlopt)
# ----------------------------------------------------------------
blocksci.cmxa: libblocksci.a blocksci.cmx
	ocamlopt -a -o $@ $^

# Generate the .cmi/.cmx from the .mli
blocksci.cmi blocksci.cmx: blocksci.mli
	ocamlc -c $<
	ocamlopt -c $<

clean:
	rm -f *.o *.a *.cmi *.cmo *.cmx *.cma

.PHONY: all clean
```

*Replace `-lblocksci` with the actual name/link‑flags that your BlockSci installation provides (e.g. `-lblocksci_core`).*  
The produced libraries can be linked like any other OCaml library:

```bash
ocamlc -I . -o myprog.byte unix.cma blocksci.cma myprog.ml
ocamlopt -I . -o myprog.native unix.cmxa blocksci.cmxa myprog.ml
```

